worker_raw_output:
{
  "summary": "The Nginx configuration has an incorrect upstream port for the 'app' service. Nginx is configured to connect to port 8001, but the 'app' service is listening on port 8000. This mismatch causes Nginx to fail connecting to the backend, resulting in 502 Bad Gateway errors. The plan is to correct the port in nginx.conf, validate the configuration, and then restart Nginx.",
  "actions": [
    {
      "type": "edit_file",
      "path": "nginx/nginx.conf",
      "operation": "replace_text",
      "old_text": "server app:8001;",
      "new_text": "server app:8000;"
    },
    {
      "type": "run_config_test",
      "target": "nginx"
    },
    {
      "type": "restart_compose_service",
      "service": "nginx"
    }
  ]
}

